const body = $json.body ? $json.body : $json;
const text = (body.transcript || '').trim();

const destMatch = /going to ([^,.]+)/i.exec(text);
const destination = destMatch ? destMatch[1].trim() : null;

const etaMatch = /(\d+)[- ]?minute/i.exec(text);
const spokenEtaMinutes = etaMatch ? parseInt(etaMatch[1], 10) : null;

const playMatch = /play (?:songs? by |some )?(.+)$/i.exec(text);
let artists = [];
if (playMatch) {
  artists = playMatch[1]
    .replace(/\band\b/gi, ',')
    .split(',')
    .map(function(a){ return a.trim().replace(/[.!?]+$/, ''); })
    .filter(function(a){ return a.length > 0; });
}

return [{
  json: {
    transcript: text,
    destination: destination,
    spokenEtaMinutes: spokenEtaMinutes,
    artists: artists,
    originLat: body.lat,
    originLng: body.lng
  }
}];

const parsed = $('Parse').item.json;

let etaSeconds = null;
let etaSource = 'spoken-fallback';
try {
  const geo = $('Geocode Destination').item.json;
  const route = $('Get Route').item.json;
  const hasGeo = Array.isArray(geo) && geo.length > 0;
  const dur = (route && route.routes && route.routes[0]) ? route.routes[0].duration : null;
  if (hasGeo && dur && dur > 30) {
    etaSeconds = Math.round(dur);
    etaSource = 'live-osrm';
  }
} catch (e) {}

if (etaSeconds === null) {
  etaSeconds = (parsed.spokenEtaMinutes || 20) * 60;
}

const catalog = [
  {id:'a1',title:'Woh Lamhe (style)',artist:'Atif Aslam',dur:258},
  {id:'a2',title:'Tera Hone Laga Hoon (style)',artist:'Atif Aslam',dur:302},
  {id:'a3',title:'Jeene Laga Hoon (style)',artist:'Atif Aslam',dur:265},
  {id:'a4',title:'Pehli Nazar Mein (style)',artist:'Atif Aslam',dur:280},
  {id:'a5',title:'Doorie (style)',artist:'Atif Aslam',dur:260},
  {id:'s1',title:'Kal Ho Naa Ho (style)',artist:'Sonu Nigam',dur:330},
  {id:'s2',title:'Sandese Aate Hain (style)',artist:'Sonu Nigam',dur:345},
  {id:'s3',title:'Abhi Mujh Mein Kahin (style)',artist:'Sonu Nigam',dur:288},
  {id:'s4',title:'Suraj Hua Maddham (style)',artist:'Sonu Nigam',dur:320},
  {id:'s5',title:'Main Yahaan Hoon (style)',artist:'Sonu Nigam',dur:290},
  {id:'g1',title:'Skyline Drive',artist:'Neon Circuit',dur:198},
  {id:'g2',title:'First Light',artist:'Aurora Kade',dur:210}
];

const artists = (parsed.artists && parsed.artists.length > 0) ? parsed.artists : [];
let pool;
if (artists.length > 0) {
  const lowered = artists.map(function(a){ return a.toLowerCase(); });
  pool = catalog.filter(function(t) {
    const artistLower = t.artist.toLowerCase();
    for (let i = 0; i < lowered.length; i++) { if (artistLower.indexOf(lowered[i]) !== -1) return true; }
    return false;
  });
  const byArtist = {};
  pool.forEach(function(t) {
    if (!byArtist[t.artist]) byArtist[t.artist] = [];
    byArtist[t.artist].push(t);
  });
  const artistNames = Object.keys(byArtist);
  const interleaved = [];
  let i = 0;
  let more = true;
  while (more) {
    more = false;
    for (let a = 0; a < artistNames.length; a++) {
      const list = byArtist[artistNames[a]];
      if (list[i]) { interleaved.push(list[i]); more = true; }
    }
    i++;
  }
  pool = interleaved;
} else {
  pool = catalog.slice(0, 6);
}

const budget = Math.max(0, etaSeconds - 20);
let queue = [];
let elapsed = 0;
const recent = [];
for (let idx = 0; idx < pool.length; idx++) {
  const track = pool[idx];
  if (elapsed + track.dur > budget) continue;
  if (recent.length > 0 && recent[recent.length - 1] === track.artist) continue;
  queue.push(track);
  recent.push(track.artist);
  elapsed += track.dur;
  if (budget - elapsed < 30) break;
}

const remaining = etaSeconds - elapsed;
const used = {};
queue.forEach(function(t){ used[t.id] = true; });
const leftover = pool.filter(function(t){ return !used[t.id]; });
let cleanCut = null;
if (remaining > 5 && leftover.length > 0) {
  const fit = leftover.filter(function(t){ return t.dur <= remaining; })[0];
  if (fit) {
    queue.push(fit);
    elapsed += fit.dur;
    cleanCut = { trackId: fit.id, fullDurationSec: fit.dur, playSeconds: fit.dur, trimmed: false, boundaryType: 'natural-end' };
  } else {
    const next = leftover[0];
    const playSeconds = Math.max(10, Math.min(next.dur, remaining));
    queue.push(next);
    elapsed += playSeconds;
    cleanCut = { trackId: next.id, fullDurationSec: next.dur, playSeconds: playSeconds, trimmed: true, boundaryType: 'faded-outro' };
  }
}

const minutes = Math.round(etaSeconds / 60);
const artistList = artists.length > 0 ? artists.join(' and ') : 'your top picks';
const confirmationText = parsed.destination
  ? 'Got it - playing ' + artistList + ', wrapping up right as you arrive in about ' + minutes + ' minutes.'
  : 'Got it - playing ' + artistList + '.';

const formattedQueue = queue.map(function(t) {
  return { id: t.id, title: t.title, artist: t.artist, durationSec: t.dur, source: 'n8n-mock' };
});

return [{
  json: {
    parsed: parsed,
    route: { etaMinutes: minutes, etaSeconds: etaSeconds, source: etaSource },
    queue: {
      queue: formattedQueue,
      totalDurationSec: elapsed,
      capped: true,
      etaSeconds: etaSeconds,
      cleanCut: cleanCut
    },
    confirmationText: confirmationText
  }
}];
